package migration

import (
        "context"
        "fmt"
        "sync"

        "github.com/grafana/grafana/apps/dashboard/pkg/migration/schemaversion"
)

// Initialize provides the migrator singleton with required dependencies and builds the map of migrations.
func Initialize(dsInfoProvider schemaversion.DataSourceInfoProvider) {
        migratorInstance.init(dsInfoProvider)
}

// ResetForTesting resets the migrator singleton for testing purposes.
func ResetForTesting() {
        migratorInstance = &migrator{
                migrations: map[int]schemaversion.SchemaVersionMigrationFunc{},
                ready:      make(chan struct{}),
        }
        initOnce = sync.Once{}
}

// Migrate migrates the given dashboard to the target version.
// This will block until the migrator is initialized.
func Migrate(ctx context.Context, dash map[string]interface{}, targetVersion int) error {
        return migratorInstance.migrate(ctx, dash, targetVersion)
}

var (
        migratorInstance = &migrator{
                migrations: map[int]schemaversion.SchemaVersionMigrationFunc{},
                ready:      make(chan struct{}),
        }
        initOnce sync.Once
)

type migrator struct {
        ready      chan struct{}
        migrations map[int]schemaversion.SchemaVersionMigrationFunc
}

func (m *migrator) init(dsInfoProvider schemaversion.DataSourceInfoProvider) {
        initOnce.Do(func() {
                m.migrations = schemaversion.GetMigrations(dsInfoProvider)
                close(m.ready)
        })
}

func (m *migrator) migrate(ctx context.Context, dash map[string]interface{}, targetVersion int) error {
        if dash == nil {
                return schemaversion.NewMigrationError("dashboard is nil", 0, targetVersion, "")
        }

        // wait for the migrator to be initialized
        <-m.ready

        // 0. Clean up dashboard properties that frontend never includes in save model
        // These properties are added by backend but frontend filters them out
        delete(dash, "__elements")
        delete(dash, "__inputs")
        delete(dash, "__requires")

        // 1. Track which panels had transformations in original input (before any defaults applied)
        // This is needed to match frontend hasOwnProperty behavior
        trackOriginalTransformations(dash)

        // 1.1. Track which panels had fieldConfig.defaults.custom in original input
        // This is needed to preserve empty custom objects that were originally present
        trackOriginalFieldConfigCustom(dash)

        // 2. Apply ALL frontend defaults FIRST (DashboardModel + PanelModel defaults)
        // This replicates the behavior of the frontend DashboardModel and PanelModel constructors
        applyFrontendDefaults(dash)

        // 2. Apply panel defaults to ALL panels (both top-level and nested in rows)
        // The frontend creates PanelModel instances for all panels, including those in rows
        if dashboardPanels, ok := dash["panels"].([]interface{}); ok {
                for _, panelInterface := range dashboardPanels {
                        if panel, ok := panelInterface.(map[string]interface{}); ok {
                                applyPanelDefaults(panel)
                        }
                }
        }

        // Apply defaults to panels inside rows (for pre-v16 dashboards)
        // Match frontend upgradeToGridLayout: only panels NOT in collapsed rows get new PanelModel() constructor
        if rows, ok := dash["rows"].([]interface{}); ok {
                showRows := shouldShowRows(rows)

                for _, rowInterface := range rows {
                        row, ok := rowInterface.(map[string]interface{})
                        if !ok {
                                continue
                        }

                        applyRowPanelDefaults(row, showRows)
                }
        }

        // 3. Ensure panel IDs are unique for ALL panels (including nested ones)
        // This matches the frontend ensurePanelsHaveUniqueIds() behavior
        ensurePanelsHaveUniqueIds(dash)

        // TODO: Probably we can check if we can migrate at the beginning of the function
        // 4. Ensure schema version is set and if not default to 0
        inputVersion := schemaversion.GetSchemaVersion(dash)
        dash["schemaVersion"] = inputVersion

        // If the schema version is older than the minimum version, with migration support,
        // we don't migrate the dashboard.
        if inputVersion < schemaversion.MIN_VERSION {
                return schemaversion.NewMinimumVersionError(inputVersion)
        }

        // 5. Run existing migration pipeline UNCHANGED
        // (All the existing v28, v29, etc. migrators run exactly as before)
        for nextVersion := inputVersion + 1; nextVersion <= targetVersion; nextVersion++ {
                if migration, ok := m.migrations[nextVersion]; ok {
                        if err := migration(ctx, dash); err != nil {
                                functionName := fmt.Sprintf("V%d", nextVersion)
                                return schemaversion.NewMigrationError("migration failed: "+err.Error(), inputVersion, nextVersion, functionName)
                        }
                        dash["schemaVersion"] = nextVersion
                }
        }

        // 6. Add built-in annotation query after all migrations are complete
        // This matches the frontend DashboardModel constructor behavior
        addBuiltInAnnotationQuery(dash)

        // 7. Clean up the dashboard to match frontend getSaveModel behavior
        // This removes properties that shouldn't be persisted and filters out default values
        cleanupDashboardForSave(dash)

        if schemaversion.GetSchemaVersion(dash) != targetVersion {
                return schemaversion.NewMigrationError("schema version not migrated to target version", inputVersion, targetVersion, "")
        }

        return nil
}

// shouldShowRows determines if row panels will be created (showRows logic)
func shouldShowRows(rows []interface{}) bool {
        for _, rowInterface := range rows {
                row, ok := rowInterface.(map[string]interface{})
                if !ok {
                        continue
                }

                collapse := schemaversion.GetBoolValue(row, "collapse")
                showTitle := schemaversion.GetBoolValue(row, "showTitle")
                repeat := schemaversion.GetStringValue(row, "repeat")

                if collapse || showTitle || repeat != "" {
                        return true
                }
        }
        return false
}

// applyRowPanelDefaults applies panel defaults to panels within a row based on frontend logic
func applyRowPanelDefaults(row map[string]interface{}, showRows bool) {
        rowPanels, ok := row["panels"].([]interface{})
        if !ok {
                return
        }

        collapse := schemaversion.GetBoolValue(row, "collapse")

        // Frontend: if (rowPanelModel && rowPanel.collapsed) { push(panel) } else { push(new PanelModel(panel)) }
        // Only non-collapsed panels get PanelModel defaults (refId: "A", overrides: [], etc.)
        applyDefaults := !showRows || !collapse

        if !applyDefaults {
                return
        }

        for _, panelInterface := range rowPanels {
                panel, ok := panelInterface.(map[string]interface{})
                if !ok {
                        continue
                }
                applyPanelDefaults(panel)
        }
}

package migration

import (
        "sort"

        "github.com/grafana/grafana/apps/dashboard/pkg/migration/schemaversion"
)

// applyFrontendDefaults applies all DashboardModel constructor defaults
func applyFrontendDefaults(dashboard map[string]interface{}) {
        // DashboardModel constructor defaults - only set defaults that the frontend actually sets
        if dashboard["title"] == nil {
                dashboard["title"] = "No Title"
        }
        if dashboard["tags"] == nil {
                dashboard["tags"] = []interface{}{}
        }
        if dashboard["timezone"] == nil {
                dashboard["timezone"] = ""
        }
        if dashboard["weekStart"] == nil {
                dashboard["weekStart"] = ""
        }
        if dashboard["editable"] == nil {
                dashboard["editable"] = true
        }
        if dashboard["graphTooltip"] == nil {
                dashboard["graphTooltip"] = float64(0)
        }
        if dashboard["time"] == nil {
                dashboard["time"] = map[string]interface{}{
                        "from": "now-6h",
                        "to":   "now",
                }
        }
        if dashboard["timepicker"] == nil {
                dashboard["timepicker"] = map[string]interface{}{}
        }
        if dashboard["schemaVersion"] == nil {
                dashboard["schemaVersion"] = float64(0)
        }
        if dashboard["fiscalYearStartMonth"] == nil {
                dashboard["fiscalYearStartMonth"] = float64(0)
        }
        // Note: version is NOT set as a default - it's managed in metadata, not spec
        if dashboard["links"] == nil {
                dashboard["links"] = []interface{}{}
        }
        // Note: gnetId is handled by the frontend constructor as: this.gnetId = data.gnetId || null;
        // But the frontend's JSON.stringify/parse in getSaveModelClone() removes null values
        // So we should NOT set gnetId to null here - let it be handled by the cleanup phase

        // Note: The frontend does NOT set defaults for these properties:
        // - liveNow: copied as-is from input data
        // - refresh: copied as-is from input data
        // - snapshot: copied as-is from input data
        // - scopeMeta: copied as-is from input data

        // Structure normalizations
        ensureTemplatingExists(dashboard)
        ensureAnnotationsExist(dashboard)

        // Note: ensurePanelsHaveUniqueIds is called AFTER applyPanelDefaults in migrate()
        // to preserve original panel IDs and match frontend behavior

        sortPanelsByGridPos(dashboard)

        // Built-in components
        initMeta(dashboard)

        // Variable cleanup
        removeNullValuesFromVariables(dashboard)
}

// applyPanelDefaults applies all PanelModel constructor defaults
func applyPanelDefaults(panel map[string]interface{}) {
        // PanelModel constructor defaults - only apply if property doesn't exist
        // This matches the frontend's defaultsDeep behavior
        if panel["gridPos"] == nil {
                panel["gridPos"] = map[string]interface{}{
                        "x": float64(0), "y": float64(0), "h": float64(3), "w": float64(6),
                }
        }
        if panel["targets"] == nil {
                panel["targets"] = []interface{}{
                        map[string]interface{}{"refId": "A"},
                }
        }
        if panel["cachedPluginOptions"] == nil {
                panel["cachedPluginOptions"] = map[string]interface{}{}
        }
        if panel["transparent"] == nil {
                panel["transparent"] = false
        }
        if panel["options"] == nil {
                panel["options"] = map[string]interface{}{}
        }
        if panel["links"] == nil {
                panel["links"] = []interface{}{}
        }

        if _, exists := panel["fieldConfig"]; !exists {
                panel["fieldConfig"] = map[string]interface{}{
                        "defaults":  map[string]interface{}{},
                        "overrides": []interface{}{},
                }
        } else {
                // Add missing defaults and overrides (matches frontend defaultsDeep behavior)
                if fieldConfig, ok := panel["fieldConfig"].(map[string]interface{}); ok {
                        if _, hasDefaults := fieldConfig["defaults"]; !hasDefaults {
                                fieldConfig["defaults"] = map[string]interface{}{}
                        }
                        if _, hasOverrides := fieldConfig["overrides"]; !hasOverrides {
                                fieldConfig["overrides"] = []interface{}{}
                        }
                }
        }
        if panel["title"] == nil {
                panel["title"] = ""
        }

        // Auto-migration logic is now applied during cleanup phase to match frontend behavior

        // Structure normalizations
        ensureQueryIds(panel)
}

// ensureTemplatingExists ensures templating.list exists
func ensureTemplatingExists(dashboard map[string]interface{}) {
        if templating, ok := dashboard["templating"].(map[string]interface{}); ok {
                if templating["list"] == nil {
                        templating["list"] = []interface{}{}
                }
        } else {
                dashboard["templating"] = map[string]interface{}{
                        "list": []interface{}{},
                }
        }
}

// ensureAnnotationsExist ensures annotations.list exists
func ensureAnnotationsExist(dashboard map[string]interface{}) {
        if annotations, ok := dashboard["annotations"].(map[string]interface{}); ok {
                if annotations["list"] == nil {
                        annotations["list"] = []interface{}{}
                }
        } else {
                dashboard["annotations"] = map[string]interface{}{
                        "list": []interface{}{},
                }
        }
}

// ensurePanelsHaveUniqueIds ensures all panels have unique IDs
func ensurePanelsHaveUniqueIds(dashboard map[string]interface{}) {
        panels := getPanels(dashboard)
        if len(panels) == 0 {
                return
        }

        ids := make(map[float64]bool)
        nextPanelId := getNextPanelId(panels)

        for _, panel := range panels {
                if panelID, ok := panel["id"].(float64); ok && panelID > 0 {
                        if ids[panelID] {
                                // Duplicate ID found, assign new one
                                panel["id"] = float64(nextPanelId)
                                nextPanelId++
                        } else {
                                // Valid unique ID, keep it
                                ids[panelID] = true
                        }
                } else {
                        // No ID or invalid ID, assign new one
                        panel["id"] = float64(nextPanelId)
                        nextPanelId++
                }
        }
}

// getNextPanelId finds the next available panel ID
func getNextPanelId(panels []map[string]interface{}) int {
        max := 0
        for _, panel := range panels {
                if panelID, ok := panel["id"].(float64); ok && panelID > 0 {
                        if int(panelID) > max {
                                max = int(panelID)
                        }
                }
        }
        return max + 1
}

// sortPanelsByGridPos sorts panels by grid position (y first, then x)
func sortPanelsByGridPos(dashboard map[string]interface{}) {
        panels := getPanels(dashboard)
        if len(panels) == 0 {
                return
        }

        sort.SliceStable(panels, func(i, j int) bool {
                panelA := panels[i]
                panelB := panels[j]

                gridPosA, okA := panelA["gridPos"].(map[string]interface{})
                gridPosB, okB := panelB["gridPos"].(map[string]interface{})

                if !okA || !okB {
                        return false
                }

                yA, okA := gridPosA["y"].(float64)
                yB, okB := gridPosB["y"].(float64)

                if !okA || !okB {
                        return false
                }

                if yA == yB {
                        // Same row, sort by x
                        xA, okA := gridPosA["x"].(float64)
                        xB, okB := gridPosB["x"].(float64)

                        if !okA || !okB {
                                return false
                        }

                        return xA < xB
                }

                return yA < yB
        })
}

// addBuiltInAnnotationQuery adds the built-in "Annotations & Alerts" annotation
func addBuiltInAnnotationQuery(dashboard map[string]interface{}) {
        annotations, ok := dashboard["annotations"].(map[string]interface{})
        if !ok {
                return
        }

        list, ok := annotations["list"].([]interface{})
        if !ok {
                return
        }

        // Check if built-in annotation already exists
        for _, item := range list {
                if annotation, ok := item.(map[string]interface{}); ok {
                        if builtIn, ok := annotation["builtIn"].(float64); ok && builtIn == 1 {
                                return // Already exists
                        }
                }
        }

        // Add built-in annotation
        builtInAnnotation := map[string]interface{}{
                "datasource": map[string]interface{}{
                        "uid":  "-- Grafana --",
                        "type": "grafana",
                },
                "name":      "Annotations & Alerts",
                "type":      "dashboard",
                "iconColor": "rgba(0, 211, 255, 1)", // DEFAULT_ANNOTATION_COLOR
                "enable":    true,
                "hide":      true,
                "builtIn":   float64(1),
        }

        // Insert at the beginning
        annotations["list"] = append([]interface{}{builtInAnnotation}, list...)
}

// initMeta initializes meta properties with defaults
func initMeta(dashboard map[string]interface{}) {
        meta, ok := dashboard["meta"].(map[string]interface{})
        if !ok {
                meta = make(map[string]interface{})
                dashboard["meta"] = meta
        }

        // Apply defaults
        if meta["canShare"] == nil {
                meta["canShare"] = true
        }
        if meta["canSave"] == nil {
                meta["canSave"] = true
        }
        if meta["canStar"] == nil {
                meta["canStar"] = true
        }
        if meta["canEdit"] == nil {
                meta["canEdit"] = true
        }
        if meta["canDelete"] == nil {
                meta["canDelete"] = true
        }

        // Derived properties
        meta["showSettings"] = meta["canEdit"]

        editable, _ := dashboard["editable"].(bool)
        if meta["canSave"] == true && !editable {
                meta["canMakeEditable"] = true
        } else {
                meta["canMakeEditable"] = false
        }

        meta["hasUnsavedFolderChange"] = false

        // If dashboard is not editable, restrict permissions
        if !editable {
                meta["canEdit"] = false
                meta["canDelete"] = false
                meta["canSave"] = false
        }
}

// removeNullValuesFromVariables removes null values from variable.current.value
func removeNullValuesFromVariables(dashboard map[string]interface{}) {
        templating, ok := dashboard["templating"].(map[string]interface{})
        if !ok {
                return
        }

        list, ok := templating["list"].([]interface{})
        if !ok || len(list) == 0 {
                return
        }

        for _, item := range list {
                if variable, ok := item.(map[string]interface{}); ok {
                        if current, ok := variable["current"].(map[string]interface{}); ok {
                                if value, exists := current["value"]; exists {
                                        // Check for null value
                                        if value == nil {
                                                delete(current, "value")
                                        } else if valueArray, isArray := value.([]interface{}); isArray {
                                                // Check for null values in arrays
                                                hasNull := false
                                                for _, v := range valueArray {
                                                        if v == nil {
                                                                hasNull = true
                                                                break
                                                        }
                                                }
                                                if hasNull {
                                                        delete(current, "value")
                                                }
                                        }
                                }
                        }
                }
        }
}

